import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Select,
  DateRangeFilter,
  SearchTextInput,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
  useViewMobileLayout,
} from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useKiemKhoListFilterState } from '../../../hooks/useKiemKhoListFilterState';
import { useKiemKhoPermissions } from '../../../hooks/useKiemKhoPermissions';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { wmsService } from '../../../services/kho/wmsService';
import type { InventoryCountDto } from '../../../services/kho/models';
import { VOUCHER_STATUS_OPTIONS } from '../../../utils/constants';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { kiemKhoPageLabels } from '../../../constants/kiemKhoPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { WmsSchemaListGrid } from '../../../components/list/WmsSchemaListGrid';
import {
  VoucherRowActionMenu,
  type VoucherRowMenuAction,
} from '../../../components/voucher-list/VoucherRowActionMenu';
import { buildPurchasingListToolbar } from '../../../features/mh/purchasingListToolbar';
import {
  DEFAULT_VOUCHER_LIST_PAGE_SIZE,
  VoucherListPagination,
  type VoucherListPageSize,
} from '../../../components/list/VoucherListPagination';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-kho-kiem-kho';
const PAGE_ID = 'kho-kiem-kho';

type InventoryCountListRow = InventoryCountDto & { lineCount: number };

const KiemKhoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const viewMobile = useViewMobileLayout();
  const { canRead, canConfirm } = useKiemKhoPermissions();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = useKiemKhoListFilterState(LIST_FILTER_SCOPE.kiemKho);

  const [warehouseId, setWarehouseId] = useState('');
  const [items, setItems] = useState<InventoryCountListRow[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSize] = useState<VoucherListPageSize>(DEFAULT_VOUCHER_LIST_PAGE_SIZE);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: InventoryCountListRow } | null>(null);

  const { warehouseOptions } = useVoucherInitData('create-inventory-count');
  const whOpts = [{ value: '', label: 'Tất cả kho' }, ...warehouseOptions];

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
  });

  const refresh = useCallback(() => {
    setReloadKey(k => k + 1);
    selection.clearActiveRow();
  }, [selection]);

  const handleSearch = useCallback(() => {
    setSearch(searchDraft.trim());
    resetPage();
    selection.clearActiveRow();
  }, [searchDraft, setSearch, resetPage, selection]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const activeRow = selection.activeRow;

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      wmsService.getInventoryCounts({
        warehouseId: warehouseId || undefined,
        status: status || undefined,
        fromDate: fromDate ? `${fromDate}T00:00:00.000Z` : undefined,
        toDate: toDate ? `${toDate}T23:59:59.999Z` : undefined,
        search: search || undefined,
        page,
        pageSize,
      })
        .then(res => {
          if (cancelled) return;
          setItems(res.items.map(r => ({ ...r, lineCount: r.lines?.length ?? 0 })));
          setTotalCount(res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, kiemKhoPageLabels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, warehouseId, status, fromDate, toDate, page, pageSize, search, dispatch, reloadKey]);

  const handleConfirm = useCallback(async (id: string) => {
    try {
      await wmsService.confirmInventoryCount(id);
      dispatchAppToast(dispatch, { message: kiemKhoPageLabels.confirmSuccess, type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, kiemKhoPageLabels.confirmError),
        type: 'error',
      });
    }
  }, [dispatch, refresh]);

  const canConfirmActive = activeRow?.status === 'Draft' && canConfirm;
  const hasRowMenu = canRead || canConfirm;

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row || action !== 'view') return;
      selection.selectActiveRow(row);
    },
    [rowMenu?.row, selection],
  );

  const toolbarProps = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      profile: 'voucher' as const,
      actions: buildPurchasingListToolbar({
        testIdPrefix: TEST_ID,
        onRefresh: refresh,
        onEditConfig: () => setShowSchemaEditor(true),
        canApprove: canConfirmActive,
        onApprove: () => activeRow && void handleConfirm(activeRow.id),
        approveLabel: 'Xác nhận',
      }),
    }),
    [refresh, canConfirmActive, activeRow, handleConfirm],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <DateRangeFilter
            label="Thời gian"
            fullWidth
            testId={`${TEST_ID}-date-range`}
            fromDate={fromDate}
            toDate={toDate}
            preset={datePreset}
            onChange={(v: DateRangeValue) => {
              applyDateRange(v.fromDate, v.toDate, v.preset);
              resetPage();
            }}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-search`,
        content: (
          <SearchTextInput
            label="Tìm kiếm"
            value={searchDraft}
            onChange={setSearchDraft}
            onSearch={handleSearch}
            placeholder="Số phiếu, kho…"
            testId={`${TEST_ID}-search-text`}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-warehouse`,
        content: (
          <Select
            label="Kho"
            value={warehouseId}
            onChange={e => { setWarehouseId(e.target.value); resetPage(); }}
            options={whOpts}
            fullWidth
            data-testid={`${TEST_ID}-filter-warehouse`}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-status`,
        content: (
          <Select
            label="Trạng thái"
            value={status}
            onChange={e => { setStatus(e.target.value); resetPage(); }}
            options={VOUCHER_STATUS_OPTIONS}
            fullWidth
            data-testid={`${TEST_ID}-filter-status`}
          />
        ),
      },
    ],
    [
      fromDate,
      toDate,
      datePreset,
      searchDraft,
      warehouseId,
      status,
      whOpts,
      applyDateRange,
      resetPage,
      setSearchDraft,
      handleSearch,
      setStatus,
    ],
  );

  const listBody = (
    <WmsSchemaListGrid
      catalogKind={LIST_UI_SCHEMA_KIND.inventoryCount}
      testIdPrefix={TEST_ID}
      rows={items}
      page={page}
      pageSize={pageSize}
      showTableLoading={showTableLoading}
      viewMobile={viewMobile}
      emptyLabel={kiemKhoPageLabels.empty}
      selection={selection}
      onRowOpenActionMenu={
        hasRowMenu
          ? ({ row, x, y }) => {
              selection.selectActiveRow(row);
              setRowMenu({ x, y, row });
            }
          : undefined
      }
    />
  );

  return (
    <div className={erp.voucherListRoot} data-voucher-list-page data-testid={`${TEST_ID}-list`}>
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: kiemKhoPageLabels.listTitle,
          titleIconClass: 'fas fa-clipboard-check',
          pageId: PAGE_ID,
        }}
        toolbarProps={toolbarProps}
        listTitle={kiemKhoPageLabels.listSubtitle}
        listRowMenuHelp={hasRowMenu}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={6}
        footer={(
          <VoucherListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearActiveRow(); }}
            onPageSizeChange={size => {
              setPageSize(size as VoucherListPageSize);
              setPage(1);
              selection.clearActiveRow();
            }}
          />
        )}
        modals={(
          <>
            <ListUiSchemaEditorModal
              testIdPrefix={TEST_ID}
              catalogKind={LIST_UI_SCHEMA_KIND.inventoryCount}
              isOpen={showSchemaEditor}
              onClose={() => setShowSchemaEditor(false)}
              title="Cấu hình hiển thị danh sách"
              onSaved={() => { setReloadKey(k => k + 1); }}
            />
            {hasRowMenu ? (
              <VoucherRowActionMenu
                open={rowMenu != null}
                x={rowMenu?.x ?? 0}
                y={rowMenu?.y ?? 0}
                onClose={() => setRowMenu(null)}
                onSelect={handleRowMenuSelect}
                testIdPrefix={TEST_ID}
                showView={canRead}
                showEdit={false}
                showViewLedger={false}
              />
            ) : null}
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default KiemKhoPage;
